import json
import base64
import hashlib
import hmac
from datetime import datetime

def lambda_handler(event, context):
    try:
        # Extract request body
        if 'body' in event:
            if event.get('isBase64Encoded', False):
                body = base64.b64decode(event['body']).decode('utf-8')
            else:
                body = event['body']
        else:
            return {
                'statusCode': 400,
                'body': json.dumps({'error': 'Missing request body'})
            }
        
        # Verify webhook signature
        headers = event.get('headers', {})
        signature = headers.get('X-Webhook-Signature') or headers.get('x-webhook-signature')
        
        if not signature:
            return {
                'statusCode': 401,
                'body': json.dumps({'error': 'Missing webhook signature'})
            }
        
        # Verify signature using HMAC
        import os
        webhook_secret = os.environ.get('WEBHOOK_SECRET', '')
        
        if not webhook_secret:
            return {
                'statusCode': 500,
                'body': json.dumps({'error': 'Webhook secret not configured'})
            }
        
        expected_signature = hmac.new(
            webhook_secret.encode('utf-8'),
            body.encode('utf-8'),
            hashlib.sha256
        ).hexdigest()
        
        if not hmac.compare_digest(signature, expected_signature):
            return {
                'statusCode': 401,
                'body': json.dumps({'error': 'Invalid webhook signature'})
            }
        
        # Parse JSON payload - DO NOT USE PICKLE
        # Pickle is unsafe for untrusted data and can lead to arbitrary code execution
        try:
            payload = json.loads(body)
        except json.JSONDecodeError as e:
            return {
                'statusCode': 400,
                'body': json.dumps({'error': f'Invalid JSON: {str(e)}'})
            }
        
        # Validate payload structure
        if not isinstance(payload, dict):
            return {
                'statusCode': 400,
                'body': json.dumps({'error': 'Payload must be a JSON object'})
            }
        
        # Validate required fields
        required_fields = ['event_type', 'user_id', 'action']
        for field in required_fields:
            if field not in payload:
                return {
                    'statusCode': 400,
                    'body': json.dumps({'error': f'Missing required field: {field}'})
                }
        
        # Sanitize and validate input
        event_type = str(payload.get('event_type', ''))[:100]
        user_id = str(payload.get('user_id', ''))[:100]
        action = str(payload.get('action', ''))[:100]
        
        # Whitelist allowed event types
        allowed_event_types = ['user.created', 'user.updated', 'user.deleted', 'action.performed']
        if event_type not in allowed_event_types:
            return {
                'statusCode': 400,
                'body': json.dumps({'error': 'Invalid event type'})
            }
        
        # Process the webhook event
        processed_data = process_webhook_event(event_type, user_id, action, payload)
        
        # Store event in database or queue for processing
        store_event(processed_data)
        
        return {
            'statusCode': 200,
            'body': json.dumps({
                'message': 'Webhook processed successfully',
                'event_id': processed_data.get('event_id')
            })
        }
        
    except Exception as e:
        # Log error securely without exposing sensitive information
        print(f"Error processing webhook: {type(e).__name__}")
        
        return {
            'statusCode': 500,
            'body': json.dumps({'error': 'Internal server error'})
        }


def process_webhook_event(event_type, user_id, action, payload):
    """Process webhook event with validated data"""
    import uuid
    
    processed_data = {
        'event_id': str(uuid.uuid4()),
        'event_type': event_type,
        'user_id': user_id,
        'action': action,
        'timestamp': datetime.utcnow().isoformat(),
        'metadata': {}
    }
    
    # Safely extract metadata with size limits
    if 'metadata' in payload and isinstance(payload['metadata'], dict):
        metadata = payload['metadata']
        for key, value in list(metadata.items())[:20]:  # Limit to 20 fields
            if isinstance(key, str) and len(key) <= 100:
                if isinstance(value, (str, int, float, bool)):
                    processed_data['metadata'][key] = value
    
    return processed_data


def store_event(event_data):
    """Store event in DynamoDB or SQS for further processing"""
    import boto3
    import os
    
    # Use DynamoDB for storage
    dynamodb = boto3.resource('dynamodb')
    table_name = os.environ.get('EVENTS_TABLE', 'webhook_events')
    table = dynamodb.Table(table_name)
    
    table.put_item(Item=event_data)
    
